param([string]$StorageAccountName,[string]$ResourceGroupName,[string]$ContainerName,[int]$Days,[string]$RuleName)
$ErrorActionPreference = 'Stop'
$action = Add-AzStorageAccountManagementPolicyAction -BaseBlobAction Delete -DaysAfterModificationGreaterThan $Days
$filter = New-AzStorageAccountManagementPolicyFilter -PrefixMatch $ContainerName -BlobType blockBlob
$newRule = New-AzStorageAccountManagementPolicyRule -Name $RuleName -Action $action -Filter $filter
$rules = @()
try {
  $existing = Get-AzStorageAccountManagementPolicy -ResourceGroupName $ResourceGroupName -StorageAccountName $StorageAccountName -ErrorAction Stop
  if ($existing -and $existing.Rules) {
    $rules = @($existing.Rules | Where-Object { $_.Name -ne $RuleName })
  }
} catch {
  Write-Host 'No existing management policy found; creating a new one.'
}
$rules += $newRule
Set-AzStorageAccountManagementPolicy -ResourceGroupName $ResourceGroupName -StorageAccountName $StorageAccountName -Rule $rules | Out-Null
$DeploymentScriptOutputs = @{}
$DeploymentScriptOutputs['ruleCount'] = [string]$rules.Count
$DeploymentScriptOutputs['rules'] = (($rules | ForEach-Object { $_.Name }) -join ',')
